<template>
    <div>
     <section class="main-content">
         <loader :is-visible="isLoading"></loader>
       <div id="divMainLeadData" v-cloak>
 
        <div class="row" v-if="callFrom!='Wizard'">
           <div class="col-md-12 padding-t_8">
             <div class="theme-primary partition-full">
               <span class="p-name text-white">{{$t('ManageLead')}}</span>
               <span class="float-right">
                 <a href="javascript:;" class="p-action-btn text-white" title="Page Tour" @click="setTourGuideSteps(0)">
                   <em class="fa fa-road" aria-hidden="true"></em>
                   <br />{{$t('PageTour')}}
                 </a>
               </span>
             </div>
           </div>
         </div>
         <div class="border p-3">
            <Form ref="LeadForm">
                <dynamic-form :lang="$i18n.locale" ref="ManageLeadForm" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="saveForm" />
            </Form>
            <modaladdindustry v-if="showaddindustryModal" callFrom='lead' @close="showaddindustryModal=false" @updatedata="UpdateSelectJson"></modaladdindustry>
            <modaladdroletitle v-if="showaddroletitleModal" @close="showaddroletitleModal=false" @updatedata="UpdateSelectJson"></modaladdroletitle>  
           <modaladdleadsource v-if="showaddleadsourceModal" callFrom="lead" @close="showaddleadsourceModal=false" @updatedata="UpdateSelectJson"></modaladdleadsource>                  
         </div>
       </div>
     </section>
 </div>
 </template>
 <script>
import DataService from "../../../services/DataService";
import modaladdindustry from '../../../components/Common/Modal/modaladdindustry.vue';
import modaladdroletitle from '../../../components/Common/Modal/modaladdroletitle.vue';
import modaladdleadsource from '../../../components/Common/Modal/modaladdleadsource.vue';
export default {
    props:{
        callFrom:null
    },
    components: {
        modaladdindustry,
        modaladdroletitle,
        modaladdleadsource
    },
    data() {
        return {
            isLoading:false,
            leadId:this.$route.params.id,
            showaddindustryModal:false,
            showaddroletitleModal:false,
            showaddleadsourceModal:false,
            phoneError:false,
            UserName:null,
            UserId:null,
            FormSchema:[],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success AddLeadDetail_a",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    onclick: this.saveForm
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.onCancel,
                    isVisible: true,
                },
            ],
        }
    },
    async created(){
        var vm =this;
        vm.UserId = vm.GetUserInfo.ID;
        vm.UserName = vm.GetUserInfo.Name;
        vm.getForm(vm.leadId);
    },
    methods:{
        getForm: function (id) {
            var ths = this;
            ths.isLoading = true;
            var url = `recordId=${id}&moduleName=CRM&subModuleCode=CRM_LEADS&langCode=en`;
            DataService.GetDynamicForm(url).then(function (response) {
                if (response != null && response.data != null) {                    
                    ths.FormSchema = ths.$refs.ManageLeadForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);
                    ths.FormSchema.forEach((group, gi) => {
                        group.Data.forEach(async  (field, fi) => {
                            if (field.name == 'industry_type_id') {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddIndustrypopup;
                            }
                            if (field.name == "channel_id") {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddLeadSourcepopup;
                            }
                            if (field.name == "role_title_id") {
                                field.config.showAddIcon = true;
                                field.config.onAddButtonClick = ths.openaddRoleTitlepopup;
                            }
                            if (field.name == 'lead_state' && field.value=='') {
                                field.config.options = null;
                            }
                            if (field.name == 'client_email') {                                
                                field.validationRules.email=true;
                                field.config.options = null;
                            }
                            if (field.name == 'lead_country' && field.value !='') {
                                var stateObj = group.Data.filter(x=>x.name=='lead_state')[0];
                                await ths.GetDropDownData('ACCOUNT_STATE', stateObj, field.value,'EDIT');
                            }
                            if (field.name == 'lead_date' && field.value == '') {
                                field.value = new Date();
                            }
                            if (field.name == 'Patient Pregnant' && field.value == '') {
                                field.value = 'NO';
                            }
                             if (field.name == 'contact_number' && field.value == '') {
                                 field.config.countryCode = 'us';
                            }
                            if (field.name == 'status_id' && field.value == '') {
                                field.value = field.config.options.filter(x=>x.name.toLowerCase()=='active')[0].value;
                            }
                            if (field.name == 'lead_owner_id' ) {
                                if(field.value == ''){
                                    field.value={label:ths.UserName,value:ths.UserId}
                                }
                                else{
                                    if(field.config.options !=null){
                                        var obj = field.config.options.filter(x=>x.value==field.value)[0];
                                        field.value={label:obj.name,value:obj.value}
                                    }else{
                                        field.value={label:ths.UserName,value:ths.UserId}
                                    }
                                }
                                field.config.onSearchChange = ths.onSearchh;
                                ths.onSearchh(null,field," ");
                            }
                            if(field.name=='lead_date'){
                               field.config = { mode: 'date', format: "M/D/YYYY" }
                            }
                            if(field.name=='expected_close_date'){
                               field.config = { mode: 'date', format: "M/D/YYYY", minDate: new Date() }
                            }
                            field.config.onChange = ths.onChangeEventForFields;
                        });
                    });          
                    ths.isLoading = false;
                }
            });
        },
        onSearchh: function (e, selctedValue, search) {            
            var vm = this;
            vm.searchSelectDataa(search, vm, selctedValue);
        },
        searchSelectDataa: function (search, ths, selctedValue) {
            this.ShowSearchDataa(search, ths, selctedValue);
        },
        ShowSearchDataa: async function (search, ths, selctedValue) {            
            var vm = this;
            var appendingUrl = `id=&&moduleName=CRM&type=CRM_USERS&search=${search}&refId=`;
            selctedValue.config.options = [];
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            await DataService.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }
                            selctedValue.config.options.push(obj);
                        })
                        vm.$refs.ManageLeadForm.UpdateKeyValue();
                    }
                }
            });
        },
        openaddIndustrypopup: function () { 
            var vm =this;
            vm.showaddindustryModal = true;
        },
        openaddRoleTitlepopup: function () {
            var vm =this;
            vm.showaddroletitleModal = true;
        },
        openaddLeadSourcepopup: function () {
            var vm =this;
            vm.showaddleadsourceModal = true;
        },
        UpdateSelectJson:function(name,json){
            let ths = this;
            ths.FormSchema.forEach((group, gi) => {
                group.Data.forEach((field, fi) => {
                    if(field.name==name){
                        if(json !=null){
                            field.config.options=[];
                            json.forEach(x=>{
                                field.config.options.push({name:x.name,value:x.value});
                            })
                        }
                    }
                    ths.$refs.ManageLeadForm.UpdateKeyValue();
                })
            })
        },
        onChangeEventForFields: function (x, y, z) {
            let ths = this;
            var vm = this;
            if (y.name == "lead_country") {
                ths.FormSchema.forEach((group, gi) => {
                    group.Data.forEach(async (field, fi) => {
                        if(field.name=='lead_state'){
                            let id = y.value;
                            await vm.GetDropDownData('ACCOUNT_STATE', field, id,null);
                        }
                    })
                })
            }
        },
        GetDropDownData: async function (type, field, id, action) {
            var vm=this;
            var url = `id=&moduleName=CRM&type=${type}&refId=${id}`;
            await DataService.getDDLData(url+ "&search=").then(response => {
                if(response.data.DATA != undefined){
                    var options = response.data.DATA;
                    field.config.options = [];
                    if(action !='EDIT'){
                        field.value='';
                    }
                    if(type=='ACCOUNT_STATE'){
                        options.forEach((item) => {
                            field.config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.ManageLeadForm.UpdateKeyValue();
                }
            });
        },
        saveForm(){
            var ths = this;
            ths.$refs.LeadForm.validate().then(result => {
                if (result) {
                    ths.isLoading = true;
                    ths.buttons[0].class += " disabled";
                    var CustomFieldArray = ths.$refs.ManageLeadForm.ConvertDynamicFormObjToCustomFieldObj(ths.FormSchema);
                    
                    CustomFieldArray.forEach((x) => {
                        if(x.field_name=='lead_owner_id'){
                            if (!ths.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if(x.field_name=='modified_by'){
                            x.field_value = vm.UserId;
                        }
                    })
                    var obj = {
                        data: CustomFieldArray,
                        moduleCode: "CRM",
                        subModuleCode: "CRM_LEADS"
                    }
                    DataService.SaveDynamicForm(JSON.stringify(obj)).then(function (response) {
                        if (response != null && response.data != null && response.data[0].Status == "Success") {
                            if(ths.leadId > 0)
                            {
                                ths.ShowAlert(ths.$t('UpdatedSuccess',[ths.$t('Lead')]),"success", true, ths.$t("Alert"));
                                ths.$router.push({ name: 'CRMLead' });
                            }
                            else
                            {
                                ths.ShowAlert(ths.$t('AddedSuccess',[ths.$t('Lead')]), "success", true,  ths.$t("Alert"));
                                ths.$router.push({ name: 'CRMLead' });
                            }
                        }
                    })
                    ths.isLoading = false;
                }
            })
        },
        onCancel:function(){
            var vm =this;
            if (vm.callFrom == 'Wizard') {
                vm.$emit('closewizard');
            } else {
                vm.$router.push({ name: 'CRMLead' });
            }
    },
    }
}
</script>
